from haystack import component, Pipeline
from collections import deque

@component
class ToolLoopDetector:
    def __init__(self, max_repeats=3, window_size=5):
        self.tool_history = deque(maxlen=window_size)
        self.max_repeats = max_repeats

    @component.output_types(has_loop=bool, loop_details=str)
    def run(self, tool_calls: list):
        if not tool_calls:
            return {"has_loop": False, "loop_details": ""}

        current_tool = (tool_calls[-1]['name'], str(tool_calls[-1].get('parameters', {})))
        self.tool_history.append(current_tool)

        # Check for repetition
        recent_calls = list(self.tool_history)
        if len(set(recent_calls)) <= 1 and len(recent_calls) >= self.max_repeats:
            return {
                "has_loop": True, 
                "loop_details": f"Repeated {current_tool[0]} {len(recent_calls)} times"
            }
        return {"has_loop": False, "loop_details": ""}

import hashlib
from haystack import component

@component
class StateLoopDetector:
    def __init__(self):
        self.seen_states = set()

    @component.output_types(loop_detected=bool, state_hash=str)
    def run(self, conversation_history: str, tool_calls: list):
        state_str = f"{conversation_history}|{str(tool_calls)}"
        state_hash = hashlib.md5(state_str.encode()).hexdigest()

        if state_hash in self.seen_states:
            return {"loop_detected": True, "state_hash": state_hash}

        self.seen_states.add(state_hash)
        return {"loop_detected": False, "state_hash": state_hash}

from haystack import component
from collections import Counter

@component
class IterationLoopDetector:
    def __init__(self, max_iterations=10):
        self.iteration_count = 0
        self.tool_pattern_history = []
        self.max_iterations = max_iterations

    @component.output_types(loop_detected=bool, iteration_count=int)
    def run(self, tool_name: str = None):
        self.iteration_count += 1
        if tool_name:
            self.tool_pattern_history.append(tool_name)

        # Pattern repetition check
        if len(self.tool_pattern_history) >= 4:
            recent_pattern = tuple(self.tool_pattern_history[-4:])
            earlier_pattern = tuple(self.tool_pattern_history[-8:-4])
            if recent_pattern == earlier_pattern:
                return {"loop_detected": True, "iteration_count": self.iteration_count}

        if self.iteration_count >= self.max_iterations:
            return {"loop_detected": True, "iteration_count": self.iteration_count}

        return {"loop_detected": False, "iteration_count": self.iteration_count}

