from haystack import component

@component
class LoopBreaker:
    @component.output_types(should_terminate=bool, final_response=str)
    def run(self, has_loop: bool, loop_details: str):
        if has_loop:
            return {
                "should_terminate": True,
                "final_response": f"Loop detected: {loop_details}. Terminating to prevent infinite execution."
            }
        return {"should_terminate": False, "final_response": ""}

from haystack import component
from collections import defaultdict

@component
class ToolMemoizer:
    def __init__(self):
        self.cache = defaultdict(list)

    @component.output_types(cached_result=dict, use_cache=bool)
    def run(self, tool_name: str, parameters: dict):
        key = (tool_name, str(sorted(parameters.items())))

        if key in self.cache and self.cache[key]:
            return {"cached_result": self.cache[key][-1], "use_cache": True}

        return {"cached_result": {}, "use_cache": False}

from haystack import component
import random

@component
class DiverseToolRouter:
    def __init__(self, available_tools: list):
        self.recent_tools = []
        self.available_tools = available_tools

    @component.output_types(suggested_tool=str, force_diversity=bool)
    def run(self, preferred_tool: str, tool_calls_history: list):
        self.recent_tools.extend([call['name'] for call in tool_calls_history[-3:]])

        # If same tool used 3+ times recently, force diversity
        if self.recent_tools.count(preferred_tool) >= 3:
            alternatives = [t for t in self.available_tools if t != preferred_tool]
            suggested = random.choice(alternatives) if alternatives else preferred_tool
            return {"suggested_tool": suggested, "force_diversity": True}

        return {"suggested_tool": preferred_tool, "force_diversity": False}
